#include <bits/stdc++.h>
using namespace std;

const int N=1e4+10;

struct Edge{
    int t,v;
};

int n,m,q;
int head[N],ver[N*4],edge[N*4],nxt[N*4],tot=1;
int dfn[N],low[N],num,stk[N],top,lst[N],now;
int len[N*2],dep[N*2],f[N][20],g[N][20],df[N],ft[N];
vector<Edge> e[N*2];

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=w,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=w,nxt[tot]=head[v],head[v]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            if(low[y]<=low[x])
                low[x]=low[y],lst[x]=edge[i];
            if(low[y]>=dfn[x]){
                now++;
                int z,cnt=0;
                do{
                    z=stk[top--],cnt+=lst[z];
                    e[now].push_back({z,cnt});
                    e[z].push_back({now,cnt});
                }while(z!=y);
                cnt+=edge[i];
                e[now].push_back({x,cnt});
                e[x].push_back({now,cnt});
                len[now]=cnt;
            }
        }else if(dfn[y]<low[x])
            low[x]=dfn[y],lst[x]=edge[i];
}

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    if(x<=n){
        for(int i=1;i<20;i++){
            f[x][i]=f[f[x][i-1]][i-1];
            g[x][i]=g[x][i-1]+g[f[x][i-1]][i-1];
        }
        for(Edge y:e[x])
            if(y.t!=fa)
                dfs(y.t,x);
        return;
    }
    int pf;
    for(Edge y:e[x])
        if(y.t==fa){
            pf=y.v;
            break;
        }
    for(Edge y:e[x])
        if(y.t!=fa){
            df[y.t]=y.v;
            ft[y.t]=x;
            f[y.t][0]=fa;
            g[y.t][0]=min(abs(y.v-pf),len[x]-abs(y.v-pf));
            dfs(y.t,x);
        }
}

int LCA(int x,int y){
    int res=0;
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=19;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            res+=g[x][i],x=f[x][i];
//    printf("res %d %d %d\n",res,x,y); 
    if(x==y)
    	return res;
    for(int i=19;i>=0;i--)
        if(f[x][i]!=f[y][i])
            res+=g[x][i]+g[y][i],x=f[x][i],y=f[y][i];
    if(ft[x]==ft[y])
        return res+min(abs(df[x]-df[y]),len[ft[x]]-abs(df[x]-df[y]));
    return res+g[x][0]+g[y][0];
}

int main(){
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        add(u,v,w);
    }
    now=n;
    tarjan(1);
    dfs(1,0);
    while(q--){
        int u,v;
        scanf("%d%d",&u,&v);
        printf("%d\n",LCA(u,v));
    }
    return 0;
}
